VALUES
  ('elementary-8b44517b-moex-00567', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於權利能力與行為能力之敘述，何者錯誤？', '["人之權利能力，始於出生，終於死亡", "受輔助宣告之人，無行為能力", "法人於法令限制內，有享受權利負擔義務之能力。但專屬於自然人之權利義務，不在此限", "權利能力及行為能力，不得拋棄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00568', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲將市價新臺幣（下同）100萬元之古董錶寄放於乙家中。某日，古董錶蒐藏家丙得知此事，向乙表 示願意高價收購該錶。乙心動不已，決定藉此中飽私囊，便花錢將該錶送交專業保養後，並因該錶 狀況甚佳，最終以150萬元出售於丙。嗣後，甲得知此事。下列敘述何者正確？', '["乙出售甲所有之古董錶於丙，係基於為甲管理事務的意思，屬於無因管理，乙得向甲請求為其支 出之保養該錶的費用，不以甲所得之利益為限", "乙出售甲所有之古董錶於丙，屬不法管理，甲僅得依侵權行為請求損害賠償100萬元", "乙出售甲所有之古董錶於丙，雖意在中飽私囊，但甲仍得享有因管理所得之利益150萬元", "乙出售甲所有之古董錶於丙，乙取得之買賣價金屬於不當得利，甲得向乙請求返還150萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00569', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲有一A地，先與乙訂立A地買賣契約，但尚未交付A地於乙且尚未辦理所有權移轉登記。嗣後， 甲與丙訂定買賣契約，將A地賣給丙，丙明知甲與乙訂約在先。下列敘述何者正確？', '["甲與丙訂立之買賣契約無效", "甲與乙訂立之買賣契約無效", "甲與乙丙之買賣契約均有效", "甲與乙及丙之買賣契約均效力未定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00570', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依法律規定、習慣或法律行為，成一公同關係之數人，基於其公同關係，而共有一物者，為公同共 有人。下列關於公同共有之敘述，何者正確？', '["公同共有人得隨時請求分割公同共有物", "公同共有人得自由處分其應有部分", "公同共有人得自由使用收益公同共有物", "公同共有人得向無權占有人請求返還公同共有物於全體公同共有人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00571', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '稱不動產役權者，謂以他人不動產供自己不動產通行、汲水、採光、眺望、電信或其他以特定便宜 之用為目的之權。下列關於不動產役權之敘述，何者錯誤？', '["不動產役權因時效而取得者，以繼續並表見者為限", "不動產役權不得由需役不動產分離而為讓與，或為其他權利之標的物", "不動產役權，不得就自己之不動產設定之", "不動產役權人因行使權利而為設置者，有維持其設置之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00572', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依民法規定，下列何者非姻親關係？', '["血親之配偶", "配偶之血親", "血親之配偶之血親", "配偶之血親之配偶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00573', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '設有爸爸甲、媽媽乙、讀國小的兒子丙與女兒丁，以及爺爺戊等人。下列何者非屬民法規定有關甲 乙對於未成年子女丙丁所為之財產上行為？', '["甲騎著學校送給丙作為模範生獎品之腳踏車上班", "乙強制把丁過年獲得之紅包存在丁之郵局帳戶", "甲開工廠要向銀行借錢，拿戊遺贈給丙之房子為銀行設定普通抵押權", "乙在戊遺贈給丁之農地上經營種苗場"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00574', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於限制辯護人與被告接見，下列敘述何者正確？', '["司法警察官得聲請限制辯護人與羈押之被告接見", "法院核發限制書，應經法官簽名", "檢察官也可以核發限制書", "對於辯護人與受逮捕的被告互通書信，得限制之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00575', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '有關刑事被告自白證明力之敘述，下列何者正確？', '["被告之自白，得作為被告有罪判決之唯一證據", "被告自白之證據能力與證明力為相同的概念", "告訴人經改列證人到庭具結之證言，得作為被告自白之補強證據", "被告自白之補強證據，以能證明被告全部犯罪事實為必要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00576', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於證據之敘述，何者正確？', '["有證據能力之證據，即可作為判斷被告是否有罪之依據", "經過合法調查之證據，即可作為判斷被告是否有罪之依據", "那些證據可以判斷被告是否有罪，全憑法院決定", "有證據能力且經合法調查之證據，即可作為判斷被告是否有罪之依據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
